/* CIDS tokens — generated from src/app/globals.css.
   Import in your root layout: `import "./cids-tokens.css";`
   (replaces the default globals; includes @import "tailwindcss") */
@import "tailwindcss";

@font-face {
  font-family: "GeistPixelSquare";
  src: url("/fonts/GeistPixelSquare.woff2") format("woff2");
  font-style: normal;
  font-weight: 400 700;
  font-display: swap;
}

:root {
  /* ── Dark token layer (market-dark palette) ──────────────────
     Single source of truth for theme colors. Components consume
     these via the @theme utilities below (bg-surface, text-fg,
     text-brand, …) — never via hardcoded hex. See DESIGN.md. */

  /* Surfaces — near-black, layered by elevation */
  --surface-dim: #030405;
  --surface-page: #090a0d;
  --surface: #101115;
  --surface-container: #17191e;
  --surface-container-high: #202228;
  --surface-bright: #2a2d34;

  /* Borders */
  --outline: #383b43;
  --outline-variant: #23262d;

  /* Foreground / text */
  --fg: #f4f4f5;
  --fg-muted: #a7abb3;
  --fg-subtle: #868b95;
  --fg-inverse: #07080a;

  /* Brand — mint-teal identity accent */
  --brand: #5ad8c4;
  --brand-hover: #78e8d7;
  --brand-bright: #a7fff0;
  --brand-subtle: #c9fbf2;
  --on-brand: #04110f;

  /* Semantic — trading + state */
  --buy: #34d399;
  --buy-strong: #10b981;
  --sell: #f87171;
  --sell-strong: #ef4444;
  --warning: #f4d35e;
  --warning-strong: #f59e0b;
  --error: #fb7185;
  --error-strong: #f43f5e;
  --info: #75a7ff;
  --info-strong: #3b82f6;
  --success: #34d399;
  --success-strong: #10b981;

  /* Tinted state surfaces (dark equivalents of light state-bg) */
  --buy-surface: #0f1f1a;
  --sell-surface: #211214;
  --warning-surface: #211d10;
  --info-surface: #111827;
  --error-surface: #221114;
  --success-surface: #0f1f1a;

  /* Identity hues — tide social layer. Per-person color for avatars,
     handle accents, and presence ONLY — never for data or state.
     Assigned deterministically (hash(wallet) % 8); --id-tide is
     reserved for the signed-in user. Muted to sit on near-black; every
     hue is AA-verified as a dark glyph and as accent text on the surface
     ladder (npm run check:contrast). Avatar fills build a radial gradient
     from the hue to color-mix(in srgb, <hue> 60%, black) — reference the
     token, never a hardcoded dark end. See DESIGN.md → Identity hues. */
  --id-tide: #5ad8c4;
  --id-coral: #e8927c;
  --id-sand: #d9b380;
  --id-lilac: #b39fd8;
  --id-sky: #7fb3d9;
  --id-moss: #93b98a;
  --id-rose: #cf8ca3;
  --id-slate: #93a1b8;

  /* Shape primitives — the radius family (DESIGN.md scale) as tokens, so
     themes and the canvas Theme Studio can reshape every component live.
     Consumed via the rounded-control/chip/card/sheet utilities mapped in
     @theme below. rounded-full (discs) is intentionally not a token. */
  --radius-control: 2px;
  --radius-chip: 4px;
  --radius-card: 8px;
  --radius-sheet: 12px;

  /* Spacing scale — 8px base grid (DESIGN.md → Spacing). Raw vars only,
     deliberately NOT mapped into Tailwind's --spacing-* namespace (that
     would silently retune p-1/p-2 site-wide). Consume via var() in
     component styles; this scale is the density lever (roadmap Phase 5:
     compact mode retunes these values, every consumer follows). */
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 40px;
  --space-6: 48px;
  --space-7: 56px;
  --space-8: 64px;

  /* Data-surface density tokens — the row grid DataTable/StatCell
     consume. The density axis re-values THESE (plus spacing + the data
     type ramp), so "comfortable" and "compact" are two values of one
     variable set, never two component forks. */
  --row-h: 44px;
  --cell-px: 12px;

  /* Z-index scale — one ladder for the whole system; consume via
     z-[var(--z-*)] (numeric z-10/20/… utilities are guard-banned in the
     DS). base < raised (popovers, HUD) < sticky (headers, bars) <
     overlay (FABs, floating layers) < modal (sheets, dialogs) < toast. */
  --z-base: 0;
  --z-raised: 10;
  --z-sticky: 20;
  --z-overlay: 30;
  --z-modal: 50;
  --z-toast: 60;

  /* Elevation — layered dark shadows (DESIGN.md → Depth). Depth comes
     from tonal layering first; shadows are secondary and deep/black.
     Consumed via shadow-card / shadow-raised / shadow-overlay utilities
     (@theme below). The brand glows are the ONLY coloured shadows the
     system allows, and they derive from --brand via color-mix — never a
     hardcoded mint. */
  --elevation-1: 0 1px 3px rgba(0, 0, 0, 0.4), 0 1px 2px rgba(0, 0, 0, 0.3);
  --elevation-2: 0 4px 12px rgba(0, 0, 0, 0.45), 0 2px 4px rgba(0, 0, 0, 0.35);
  --elevation-3: 0 24px 80px rgba(0, 0, 0, 0.7);
  --glow-brand: 0 1px 2px rgba(4, 17, 15, 0.4),
    0 4px 8px color-mix(in srgb, var(--brand) 20%, transparent);
  --glow-brand-strong: 0 4px 8px
      color-mix(in srgb, var(--brand) 20%, transparent),
    0 12px 24px color-mix(in srgb, var(--brand) 12%, transparent);

  /* Motion primitives — durations and easings as separate tokens, plus
     the composite duration+easing pairs components consume via CSS
     (transition: transform var(--motion-fast)). fast = state/hover;
     settle = enter/morph; spring = playful feedback on human actions
     only (react, follow). Honors prefers-reduced-motion via the global
     reset below. */
  --duration-fast: 150ms;
  --duration-settle: 200ms;
  --duration-spring: 250ms;
  --ease-settle: cubic-bezier(0.2, 0.8, 0.2, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --motion-fast: var(--duration-fast) ease-out;
  --motion-settle: var(--duration-settle) var(--ease-settle);
  --motion-spring: var(--duration-spring) var(--ease-spring);

  /* Financial type ramp — sizes as tokens (utilities text-data-* via
     @theme; the .data-* classes below consume the same vars). */
  --text-data-lg-size: 1.125rem;
  --text-data-lg-size-desktop: 1.875rem;
  --text-data-md-size: 0.875rem;
  --text-data-sm-size: 0.75rem;
  --font-pixel-stack: "GeistPixelSquare", "IBM Plex Mono", ui-monospace,
    monospace;

  /* Back-compat aliases (kept so legacy var reads still resolve) */
  --background: var(--surface-page);
  --foreground: var(--fg);

  /* Wallet modal backdrop */
  --wallet-backdrop-rgb: 3 4 5;
  --wallet-backdrop-opacity: 0.6;
  --wallet-backdrop-blur: 28px;
}

/* ── Theme: mono ─────────────────────────────────────────────
   Monochrome variant — pure-neutral surface ladder for depth and a
   white "ink" brand. Functional colors (buy/sell/warning/info/error)
   and identity hues are deliberately KEPT: everything is grayscale
   except the signal. Activate with <html data-theme="mono">; every
   component re-skins via the same token names. Values are AA-verified
   per theme by npm run check:contrast. */
[data-theme="mono"] {
  --surface-dim: #050505;
  --surface-page: #0b0b0b;
  --surface: #121212;
  --surface-container: #181818;
  --surface-container-high: #212121;
  --surface-bright: #2b2b2b;

  --outline: #3d3d3d;
  --outline-variant: #262626;

  --fg: #f5f5f5;
  --fg-muted: #a6a6a6;
  --fg-subtle: #8a8a8a;

  --brand: #ffffff;
  --brand-hover: #e6e6e6;
  --brand-bright: #ffffff;
  --brand-subtle: #d4d4d4;
  --on-brand: #0b0b0b;

  --wallet-backdrop-rgb: 5 5 5;
}

/* ── Theme: light ────────────────────────────────────────────
   The adaptability proof (cids-roadmap Phase 3): the same token names,
   re-valued for a white canvas. Cards are white on a cool-gray page;
   depth still comes from tonal layering. Identity hues shift to their
   dark-jewel equivalents (light surfaces force text-dark hues — both
   contrast rules point the same way); the avatar glyph inverts to
   near-white via --fg-inverse. Brand becomes deep teal so text-brand
   holds AA on white; on-brand flips to near-white accordingly.
   AA-verified per theme by npm run check:contrast. */
[data-theme="light"] {
  --surface-dim: #e7e9ee;
  --surface-page: #f5f6f8;
  --surface: #fbfcfd;
  --surface-container: #ffffff;
  --surface-container-high: #f1f3f6;
  --surface-bright: #eef0f4;

  --outline: #c3c9d3;
  --outline-variant: #e3e6eb;

  --fg: #15181d;
  --fg-muted: #4d5560;
  --fg-subtle: #69707c;
  --fg-inverse: #fbfcfe;

  --brand: #0c6e63;
  --brand-hover: #0a5d54;
  --brand-bright: #084f47;
  --brand-subtle: #baded7;
  --on-brand: #f4fbf9;

  --buy: #047857;
  --buy-strong: #065f46;
  --sell: #b91c1c;
  --sell-strong: #991b1b;
  --warning: #92610a;
  --warning-strong: #78500a;
  --error: #be123c;
  --error-strong: #9f1239;
  --info: #1d4ed8;
  --info-strong: #1e40af;
  --success: #047857;
  --success-strong: #065f46;

  --buy-surface: #e2f5ec;
  --sell-surface: #fde7e7;
  --warning-surface: #faf0d8;
  --info-surface: #e6edfc;
  --error-surface: #fbe7ed;
  --success-surface: #e2f5ec;

  --id-tide: #0c6e63;
  --id-coral: #a83a10;
  --id-sand: #7d5405;
  --id-lilac: #6747a8;
  --id-sky: #14618f;
  --id-moss: #3d6636;
  --id-rose: #a03354;
  --id-slate: #45536b;

  --elevation-1: 0 1px 3px rgba(23, 30, 40, 0.1), 0 1px 2px rgba(23, 30, 40, 0.08);
  --elevation-2: 0 4px 12px rgba(23, 30, 40, 0.12), 0 2px 4px rgba(23, 30, 40, 0.08);
  --elevation-3: 0 24px 80px rgba(23, 30, 40, 0.25);

  --wallet-backdrop-rgb: 231 233 238;
}

/* ── Theme: violet ───────────────────────────────────────────
   White-label demo (cids-roadmap Phase 3): proves re-branding is ONE
   block — swap the accent family (+ the reserved "you" hue, which
   follows brand) and touch nothing else. Everything else falls back
   to :root (market-dark). */
[data-theme="violet"] {
  --brand: #a78bfa;
  --brand-hover: #bfa7fc;
  --brand-bright: #d8c9ff;
  --brand-subtle: #e9dfff;
  --on-brand: #17102b;

  --id-tide: #a78bfa;
}

/* ── Density: compact ────────────────────────────────────────
   The terminal axis (cids-roadmap Phase 5). Activate with
   <html data-density="compact"> (canvas Theme Studio has the switch).
   Orthogonal to themes — it re-values the spacing scale, the financial
   type ramp, and the row grid; token-consuming components follow with
   zero component changes. Touch targets: interactive controls keep
   their own heights (Button/IconButton do not shrink below 28px). */
[data-density="compact"] {
  --space-1: 6px;
  --space-2: 12px;
  --space-3: 18px;
  --space-4: 24px;
  --space-5: 30px;
  --space-6: 36px;
  --space-7: 42px;
  --space-8: 48px;

  --text-data-lg-size: 1rem;
  --text-data-lg-size-desktop: 1.5rem;
  --text-data-md-size: 0.8125rem;
  --text-data-sm-size: 0.6875rem;

  --row-h: 32px;
  --cell-px: 8px;
}

@theme inline {
  --color-background: var(--surface-page);
  --color-foreground: var(--fg);

  --color-surface-dim: var(--surface-dim);
  --color-surface-page: var(--surface-page);
  --color-surface: var(--surface);
  --color-surface-container: var(--surface-container);
  --color-surface-container-high: var(--surface-container-high);
  --color-surface-bright: var(--surface-bright);

  --color-outline: var(--outline);
  --color-outline-variant: var(--outline-variant);

  --color-fg: var(--fg);
  --color-fg-muted: var(--fg-muted);
  --color-fg-subtle: var(--fg-subtle);
  --color-fg-inverse: var(--fg-inverse);

  --color-brand: var(--brand);
  --color-brand-hover: var(--brand-hover);
  --color-brand-bright: var(--brand-bright);
  --color-brand-subtle: var(--brand-subtle);
  --color-on-brand: var(--on-brand);

  --color-buy: var(--buy);
  --color-buy-strong: var(--buy-strong);
  --color-sell: var(--sell);
  --color-sell-strong: var(--sell-strong);
  --color-warning: var(--warning);
  --color-warning-strong: var(--warning-strong);
  --color-error: var(--error);
  --color-error-strong: var(--error-strong);
  --color-info: var(--info);
  --color-info-strong: var(--info-strong);
  --color-success: var(--success);
  --color-success-strong: var(--success-strong);

  --color-buy-surface: var(--buy-surface);
  --color-sell-surface: var(--sell-surface);
  --color-warning-surface: var(--warning-surface);
  --color-info-surface: var(--info-surface);
  --color-error-surface: var(--error-surface);
  --color-success-surface: var(--success-surface);

  /* Identity hues — flat-fill / text-accent utilities (text-id-lilac,
     bg-id-coral). Avatar gradients reference the raw var() instead. */
  --color-id-tide: var(--id-tide);
  --color-id-coral: var(--id-coral);
  --color-id-sand: var(--id-sand);
  --color-id-lilac: var(--id-lilac);
  --color-id-sky: var(--id-sky);
  --color-id-moss: var(--id-moss);
  --color-id-rose: var(--id-rose);
  --color-id-slate: var(--id-slate);

  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);

  /* Shape utilities: rounded-control / rounded-chip / rounded-card /
     rounded-sheet (+ side variants like rounded-t-sheet) */
  --radius-control: var(--radius-control);
  --radius-chip: var(--radius-chip);
  --radius-card: var(--radius-card);
  --radius-sheet: var(--radius-sheet);

  /* Elevation utilities: shadow-card / shadow-raised / shadow-overlay +
     the two brand glows (the only coloured shadows allowed). */
  --shadow-card: var(--elevation-1);
  --shadow-raised: var(--elevation-2);
  --shadow-overlay: var(--elevation-3);
  --shadow-glow-brand: var(--glow-brand);
  --shadow-glow-brand-strong: var(--glow-brand-strong);

  /* Easing utilities: ease-settle / ease-spring (durations are consumed
     via the composite --motion-* vars or duration-[var(--duration-*)]). */
  --ease-settle: var(--ease-settle);
  --ease-spring: var(--ease-spring);

  /* Financial type ramp utilities: text-data-lg / -md / -sm (pair with
     font-pixel + tabular-nums, or use the .data-* composite classes). */
  --text-data-lg: var(--text-data-lg-size);
  --text-data-lg--line-height: 1.2;
  --text-data-md: var(--text-data-md-size);
  --text-data-md--line-height: 1.2;
  --text-data-sm: var(--text-data-sm-size);
  --text-data-sm--line-height: 1.2;
  --font-pixel: var(--font-pixel-stack);
}

body {
  background: var(--surface-page);
  color: var(--fg);
  font-family: var(--font-geist-sans), ui-sans-serif, system-ui, sans-serif;
}

html {
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.16) transparent;
}

/* Accessibility — keyboard focus ring.
   Visible only for keyboard / programmatic focus (:focus-visible), never on
   pointer interaction. Uses the brand accent via `outline` (not box-shadow) so
   it never shifts layout. Component focus styles are additive, not a
   replacement. See DESIGN.md → Accessibility. */
:focus-visible {
  outline: 2px solid var(--brand);
  outline-offset: 2px;
}

/* Financial data type ramp (DESIGN.md → Typography). Documented there but
   previously only defined in the prototype theme; wired here so components
   render numbers in Geist Pixel Square instead of falling back to sans.
   tabular-nums keeps columns of figures aligned. */
.data-lg,
.data-md,
.data-sm {
  font-family: var(--font-pixel-stack);
  font-weight: 400;
  line-height: 1.2;
  font-variant-numeric: tabular-nums;
}
.data-lg {
  font-size: var(--text-data-lg-size);
}
.data-md {
  font-size: var(--text-data-md-size);
}
.data-sm {
  font-size: var(--text-data-sm-size);
}
@media (min-width: 768px) {
  .data-lg {
    font-size: var(--text-data-lg-size-desktop);
  }
}

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Spring-pop — reaction feedback on human actions (DESIGN.md → Motion,
   budgeted playfulness). Uses --motion-spring (250ms overshoot bezier).
   Neutralized by the prefers-reduced-motion reset below. */
/* Digit roll — RollingNumber's on-change transition (discrete, never
   looping; data surfaces stay calm). Neutralized by the reduced-motion
   reset below. */
@keyframes roll-in {
  from {
    opacity: 0;
    transform: translateY(0.45em);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.animate-roll-in {
  animation: roll-in var(--motion-settle);
}

@keyframes pop {
  0% {
    transform: scale(1);
  }
  45% {
    transform: scale(1.3);
  }
  100% {
    transform: scale(1);
  }
}
.animate-pop {
  animation: pop var(--motion-spring);
}

/* Accordion open/close — Radix measures the panel into
   --radix-accordion-content-height; animating height needs the padding
   on an inner element. Neutralized by the reduced-motion reset below. */
@keyframes accordion-down {
  from {
    height: 0;
  }
  to {
    height: var(--radix-accordion-content-height);
  }
}
@keyframes accordion-up {
  from {
    height: var(--radix-accordion-content-height);
  }
  to {
    height: 0;
  }
}
.animate-accordion-down {
  animation: accordion-down var(--motion-settle);
}
.animate-accordion-up {
  animation: accordion-up var(--motion-settle);
}

/* Indeterminate Progress — the one sanctioned looping animation:
   unknown-duration waits only, quiet by design. Neutralized by the
   reduced-motion reset below. */
@keyframes progress-slide {
  from {
    transform: translateX(-100%);
  }
  to {
    transform: translateX(300%);
  }
}
.animate-progress-slide {
  animation: progress-slide 1.2s var(--ease-settle) infinite;
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.16);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.26);
}
.scrollbar-hide {
  scrollbar-width: none;
}
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* Jupiter Unified Wallet modal backdrop controls */
dialog[aria-modal="true"] {
  background-color: rgb(
    var(--wallet-backdrop-rgb) / var(--wallet-backdrop-opacity)
  ) !important;
  --tw-backdrop-blur: blur(var(--wallet-backdrop-blur)) !important;
  backdrop-filter: var(--tw-backdrop-blur) var(--tw-backdrop-brightness)
    var(--tw-backdrop-contrast) var(--tw-backdrop-grayscale)
    var(--tw-backdrop-hue-rotate) var(--tw-backdrop-invert)
    var(--tw-backdrop-opacity) var(--tw-backdrop-saturate)
    var(--tw-backdrop-sepia) !important;
  -webkit-backdrop-filter: var(--tw-backdrop-blur)
    var(--tw-backdrop-brightness) var(--tw-backdrop-contrast)
    var(--tw-backdrop-grayscale) var(--tw-backdrop-hue-rotate)
    var(--tw-backdrop-invert) var(--tw-backdrop-opacity)
    var(--tw-backdrop-saturate) var(--tw-backdrop-sepia) !important;
}
